SELECT avg_rating
FROM movie_stats
WHERE movie_id = 1;

SELECT avg_rating
FROM movie_stats
WHERE total_ratings > 5;

SELECT movie_id
FROM movie_stats
WHERE avg_rating = (SELECT MAX(avg_rating) FROM movie_stats);

SELECT AVG(imdb_rating) AS average_imdb_rating
FROM movies
WHERE movie_id IN (SELECT movie_id FROM ratings);
